// 1. Pega o que está salvo na memória
let valorAtual = flow.get("posicaoSlider") || 0;

// 2. Identifica quem enviou a mensagem
if (msg.topic === "adicionar") {
    valorAtual += 1;
}
else if (msg.topic === "subtrair") {
    valorAtual -= 1;
}
else {
    // Se a mensagem veio do SLIDER, atualizamos a memória
    valorAtual = msg.payload;
}

// 3. Travas de segurança (0 a 300 no Slider)
if (valorAtual > 300) valorAtual = 300;
if (valorAtual < 0) valorAtual = 0;

// 4. Salva o valor atualizado
flow.set("posicaoSlider", valorAtual);

// 5. Preparando as saídas
// msg1 vai para o Slider (Sincronismo 0-300)
let msg1 = { payload: valorAtual };

// msg2 vai para o seu processo (Valor dividido por 2)
let msg2 = { payload: valorAtual / 2 };

// 6. Retorna as duas mensagens em suas respectivas saídas
return [msg1, msg2];

// 1. Pega o que está salvo na memória
let valorAtual = flow.get("numGarrafas") || 0;

// 2. Identifica quem enviou a mensagem
if (msg.topic === "adicionar") {
    valorAtual += 1;
}
else if (msg.topic === "subtrair") {
    valorAtual -= 1;
}
else {
    // Se a mensagem NÃO veio dos botões, ela veio do SLIDER.
    // Então atualizamos a memória com a posição real que você arrastou.
    valorAtual = msg.payload;
}

// 3. Travas de segurança
if (valorAtual > 300) valorAtual = 300;
if (valorAtual < 0) valorAtual = 0;

// 4. Salva o valor atualizado para a próxima vez
flow.set("numGarrafas", valorAtual);

// 5. Envia o valor de volta para o Slider (para sincronizar)
msg.payload = valorAtual;
return msg;

let status = flow.get("botoes_status") || { start: true, stop: false, enviar: true };

let comando = msg.topic;

if (comando === "enviar") {

    // Apenas carrega os dados. Não inicia o movimento.

    status.enviar = true;

    flow.set("dados_carregados", true);

    node.warn("Configurações enviadas ao sistema.");

}

else if (comando === "start") {

    // Verifica se os dados já foram enviados antes de permitir o Start

    if (flow.get("dados_carregados")) {

        status.start = false;

        status.stop = true;

        status.enviar = false;

        flow.set("processo_ativo", true); // Agora o Start ativa o hardware

    } else {

        node.error("Erro: Envie as configurações antes de dar Start!");

    }

}

else if (comando === "stop") {

    status.start = true;

    status.stop = false;

    status.enviar = true;

    flow.set("processo_ativo", false); // Para tudo imediatamente

}



flow.set("botoes_status", status);



return [

    { enabled: status.start },

    { enabled: status.stop },

    { enabled: status.enviar }

];

// 1. Pega o valor da memória (flow)
// O parseFloat garante que o valor seja tratado como número decimal
let valorAtual = parseFloat(flow.get("resolucaoK")) || 0;

// 2. Lógica de incremento e decremento
if (msg.topic === "adicionar") {
    valorAtual += 0.1;
}
else if (msg.topic === "subtrair") {
    valorAtual -= 0.1;
}

// 3. Correção de precisão matemática
// O JS pode gerar 0.300000000004; isso trava em 1 casa decimal
valorAtual = Math.round(valorAtual * 10) / 10;

// 4. Travas de segurança (Limites de 0 a 100)
if (valorAtual > 100) valorAtual = 100;
if (valorAtual < 0) valorAtual = 0;

// 5. Salva o valor atualizado na memória
flow.set("resolucaoK", valorAtual);

// 6. Prepara a mensagem de saída para o nó Text
msg.payload = valorAtual;
return msg;

// 1. Recebe o valor dos mLs vindo da Saída 1 do nó anterior
let volumeML = msg.payload;

// 2. Busca na memória o valor da resolução (aquele que muda de 0.1 em 0.1)
let divisorK = flow.get("resolucaoK") || 1; // Padrão 1 para evitar divisão por zero

// 3. Realiza o cálculo da divisão
let resultadoOriginal = volumeML / divisorK;

// 4. Aplica o arredondamento (Math.round)
// 272.72 -> 273
// 272.50 -> 273
// 272.49 -> 272
let resultadoArredondado = Math.round(resultadoOriginal);

// 5. Prepara a saída
msg.payload = resultadoArredondado;

flow.set("resultado_arredondado", resultadoArredondado);

// Opcional: Adicionar detalhes extras na msg para depuração
msg.original = resultadoOriginal;
msg.divisorUsado = divisorK;

return msg;

// Configurações de tempo
const tempoReset = 100;
const tempoAceso = 10;
const tempoApagado = 10;

node.warn(msg.payload)

const pulsosML = msg.payload.ml;
const pulsosGarrafas = msg.payload.garrafas;

const delay = (ms) => new Promise(resolve => setTimeout(resolve, ms));

(async () => {

    // LIMPEZA INICIAL
    node.send([{ payload: 0 }, { payload: 0 }, { payload: 0 }]);
    await delay(500);

    // RESET
    node.send([{ payload: 1 }, null, null, null]);
    await delay(tempoReset);

    node.send([{ payload: 0 }, null, null, null]);
    await delay(500);

    // PULSOS ML
    for (let i = 1; i <= pulsosML; i++) {

        node.warn("Pulso ML nº: " + i);

        node.send([null, { payload: 1 }, null, null]);
        await delay(tempoAceso);

        node.send([null, { payload: 0 }, null, null]);
        await delay(tempoApagado);
    }

    await delay(300);

    // PULSOS GARRAFAS
    for (let i = 1; i <= pulsosGarrafas; i++) {

        node.warn("Pulso Garrafa nº: " + i);

        node.send([null, null, { payload: 1 }, null]);
        await delay(tempoAceso);

        node.send([null, null, { payload: 0 }, null]);
        await delay(tempoApagado);
    }
  node.send([null, null, null, { payload: 1 }]);
    await delay(tempoReset);

    node.send([null, null, null, { payload: 0 }]);
    await delay(500);
})();

return null;
